import{_ as n,o as t,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"13. Prevention And Management Of Workplace Bullying","description":"","frontmatter":{"title":"13. Prevention And Management Of Workplace Bullying","eba":"Medical Specialists 2022-2026","topics":["ohs"]},"headers":[],"relativePath":"ebas/medical-specialists/consultation-disputes/13-prevention-and-management-of-workplace-bullying.md","filePath":"ebas/medical-specialists/consultation-disputes/13-prevention-and-management-of-workplace-bullying.md"}'),i={name:"ebas/medical-specialists/consultation-disputes/13-prevention-and-management-of-workplace-bullying.md"};function r(s,e,l,p,g,c){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_13-prevention-and-management-of-workplace-bullying" tabindex="-1">13. Prevention And Management Of Workplace Bullying <a class="header-anchor" href="#_13-prevention-and-management-of-workplace-bullying" aria-label="Permalink to &quot;13. Prevention And Management Of Workplace Bullying&quot;">​</a></h1><p><strong>13.1</strong> Purpose</p><p><strong>(a)</strong> This clause concerns the prevention and management of Workplace bullying and requires employers to take actions consistent with their obligations under the OHS Act. Workplace bullying is an occupational health and safety risk.</p><p><strong>(b)</strong> Workplace bullying can happen in any workplace. Under certain conditions, anyone could be capable of bullying-type behaviour.</p><p><strong>(c)</strong> Workplace bullying can have an impact on an individual’s health and affect their ability to do their job. It can also contribute to loss of productivity, staff turnover, absenteeism, low morale and financial costs.</p><p><strong>(d)</strong> It is in the interests of all parties including Employers, Employees who raise complaints, Employees about whom complaints are made and their representatives, that concerns about behaviour that may be workplace bullying are addressed quickly, fairly and sensitively and with the intention of ensuring a safe working environment for everyone.</p><p><strong>13.2</strong> Definitions</p><p><strong>(a)</strong> Workplace Bullying is repeated, unreasonable behaviour directed at an employee or group of employees that creates a risk to health and safety. Reasonable management action carried out in a reasonable manner is not bullying.</p><p>Examples</p><p>Examples of workplace bullying include repeated:</p><p><strong>(i)</strong> Verbal abuse. For example, being sworn at, threatened, insulted, continual inappropriate and/or invalid criticism, name calling, practical jokes, unjustified threats of punishment, belittling and humiliation, gossip and malicious rumours, inappropriate language, yelling.</p><p><strong>(ii)</strong> Unreasonable demands, unnecessary pressure and impossible deadlines, which are targeted at an employee or group of employees</p><p><strong>(iii)</strong> Unfair allocation of tasks and/or working hours. For example, repeatedly requiring a particular person to stay back after hours or rostering them onto night duty</p><p><strong>(iv)</strong> Undermining a person’s work performance, recognition or position, especially with their managers or co-workers</p><p><strong>(v)</strong> Hostile behaviour toward an employee or group of Employees. For example, excluding them from conversations or various activities</p><p>Examples of reasonable management action carried out in a reasonable manner include:</p><p><strong>(vi)</strong> Genuine and reasonable instructions;</p><p><strong>(vii)</strong> Rostering and allocating working hours, where the requirements are reasonable; and</p><p><strong>(viii)</strong> Constructively delivered feedback or counselling intended to help employees to improve their work performance or the standard of their behaviour.</p><p><strong>(b)</strong> OHS Act means the Occupational and Health Safety Act 2004.</p><p><strong>13.3</strong> Prevention - General</p><p><strong>(a)</strong> Employers have a duty under the OHS Act to provide and maintain, so far as is reasonably practicable, a working environment that is safe and without risks to health.</p><p><strong>(b)</strong> Employer obligations include:</p><p><strong>(i)</strong> providing and maintaining systems of work that are, so far as is reasonably practicable, safe and without risks to health;</p><p><strong>(ii)</strong> consulting with Employees who are or who are likely to be directly affected by a health and safety matter.</p><p><strong>(c)</strong> Prevention is the key to providing a safe working environment.</p><p><strong>13.4</strong> Prevention - Policy</p><p><strong>(a)</strong> Each Employer will have a workplace policy and procedure for workplace bullying.</p><p><strong>(b)</strong> A workplace policy should state:</p><p><strong>(i)</strong> a commitment to providing Employees with a healthy and safe working environment;</p><p><strong>(ii)</strong> the standard of behaviour expected of all Employees, including examples of what is and what is not workplace bullying;</p><p><strong>(iii)</strong> how the policy applies in connection with work and work-related events and activities;</p><p><strong>(iv)</strong> that the policy covers all communication, including text messages, email and social media;</p><p><strong>(v)</strong> how and where employees can report allegations of workplace bullying;</p><p><strong>(vi)</strong> that reports of workplace bullying are taken seriously and are responded to by the Employer impartially and confidentially;</p><p><strong>(vii)</strong> what can happen if the policy is not followed;</p><p><strong>(viii)</strong> how the Employer will respond to allegations of workplace bullying that have been reported;</p><p><strong>(ix)</strong> how reports will be investigated;</p><p><strong>(x)</strong> where to get more information.</p><p><strong>13.5</strong> Early Intervention</p><p><strong>(a)</strong> It is recognised that early intervention is critical to ensuring both a safe workplace and fairness to all parties. The objective of early intervention is to:</p><p><strong>(i)</strong> establish appropriate behaviour;</p><p><strong>(ii)</strong> prevent inappropriate behaviour; and</p><p><strong>(iii)</strong> resolve issues without a formal report or investigation.</p><p><strong>(b)</strong> Early intervention may include:</p><p><strong>(i)</strong> self-managing a situation; and</p><p><strong>(ii)</strong> seeking assistance from someone else such as a manager, supervisor, medical workforce unit or human resources.</p><p><strong>(c)</strong> Training plays an important role in the early intervention of workplace bullying. Employers should ensure employees are trained to recognise bullying behaviour and to adjust their behaviour accordingly before it becomes an issue.</p><p><strong>13.6</strong> Managing Workplace Bullying – General Principles</p><p>Where it is necessary to conduct an investigation regarding potential workplace bullying, the following principles will apply:</p><p><strong>(a)</strong> The Doctor who is the subject of the concern will be provided with natural justice including but not limited to:</p><p><strong>(i)</strong> explaining the process and the specific allegations in writing;</p><p><strong>(ii)</strong> advising the that they may be represented by the Association, or other advocate, at any time;</p><p><strong>(iii)</strong> the purpose of any meetings is identified in advance; and</p><p><strong>(iv)</strong> the Doctor is provided with an opportunity to respond via documentation, an interview or a combination of both.</p><p><strong>(b)</strong> The investigator and, in turn, the decision-maker will act in good faith and without bias which:</p><p><strong>(i)</strong> means the person conducting the investigation has no preconceived opinions, vested interests or prior personal involvement in the matter; and</p><p><strong>(ii)</strong> does not necessarily mean excluding a person from the same organisation as the employee, from conducting an investigation or making a decision.</p><p><strong>(c)</strong> The Employer shall provide an unredacted report to the Doctors and their representative/s, including the Association where relevant, upon request.</p><p><strong>13.7</strong> Where an external investigator is appointed</p><p>Where the Employer decides to appoint an external investigator, the Employer shall either:</p><p><strong>(a)</strong> Select an investigator from the DH ‘preferred provider’ list; or</p><p><strong>(b)</strong> Appoint an investigator following timely consultation with the representative of the Employee parties, including the Association, where relevant. The Employer may appoint an investigator without consultation where no response is received from the Union within 5 days following the Association being notified.</p><p>Consultation in this subclause 13.7 has its ordinary meaning and does not refer to consultation as set out at <a href="/eba/ebas/medical-specialists/consultation-disputes/9-consultation.html">clause 9</a> and shall be conducted efficiently having regard for the health and safety of the employees.</p><p><strong>13.8</strong> More information</p><p>Further information about workplace bullying and principles to manage and resolve bullying matters can be found at:</p><p><strong>(a)</strong> www.worksafe.vic.gov.au/bullying-workplace</p><p><strong>(b)</strong> Victorian Public Sector Standards Commissioner’s Guide – Managing Poor Behaviour in the Workplace.</p><p><strong>13.9</strong> Employers will review and use for guidance the Best Practice Guide developed jointly by the Association and VHIA and make it available at the workplace.</p><p>Plain language terms: bullying.</p>',70)])])}const u=n(i,[["render",r]]);export{h as __pageData,u as default};
